export const getLogoValues = (attributes = {}) => {
	const logo_choice = Number.isInteger(attributes.logo_choice) ? attributes.logo_choice : 0;
	const fill_font = attributes.fill_font || '#ffffff';
	const fill_page = attributes.fill_page || '#cc0000';
	const fill_side = attributes.fill_side || '#990000';
	const circle_stroke = attributes.circle_stroke || '#000000';
	const circle_stroke_width = attributes.circle_stroke_width || 2;
	const circle_fill = attributes.circle_fill || 'transparent';
	const viewBox = `${-19 - circle_stroke_width / 2} ${-9 - circle_stroke_width / 2} ${98 + circle_stroke_width} ${97 + circle_stroke_width}`;

	return {
		logo_choice,
		fill_font,
		fill_page,
		fill_side,
		circle_stroke,
		circle_stroke_width,
		circle_fill,
		viewBox,
	};
};

const resolveValues = (props) => {
	if (props?.values) {
		return props.values;
	}

	return getLogoValues(props?.attributes);
};

